import { css, cx } from '@emotion/css'
import { useReactiveRef } from '@guanghechen/react-hooks'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { GomokuActionType, GomokuContextType } from '@kyokuya/react-game-gomoku-core'
import GameRunningIcon from '@mui/icons-material/Pause'
import RetractIcon from '@mui/icons-material/Redo'
import RefreshIcon from '@mui/icons-material/Refresh'
import { Button, Dialog, DialogActions, DialogContent, IconButton, Tooltip } from '@mui/material'
import PropTypes from 'prop-types'
import React from 'react'

export interface IGameToolbarProps {
  containerRef: React.RefObject<HTMLDivElement>
}

export const GameToolbar: React.FC<IGameToolbarProps> = props => {
  const { state, dispatch } = React.useContext(GomokuContextType)
  const stateRef = useReactiveRef(state)
  const [restartDialogVisible, setRestartDialogVisible] = React.useState<boolean>(false)

  const actions = React.useMemo(
    () => ({
      // Restart game.
      restart: (): void => {
        setRestartDialogVisible(false)
        dispatch({ type: GomokuActionType.RESTART })
      },
      start: (): void => {
        const { gameStatus } = stateRef.current
        if (gameStatus === GameRunningStatus.PENDING || gameStatus === GameRunningStatus.FINISHED) {
          actions.restart()
        } else {
          setRestartDialogVisible(true)
        }
      },
      // Pause game.
      pause: (): void => {
        dispatch({ type: GomokuActionType.PAUSE })
      },
      // Retract.
      retract: (): void => {
        dispatch({ type: GomokuActionType.RETRACT })
      },
      closeDialog: (): void => {
        setRestartDialogVisible(false)
      },
    }),
    [dispatch, stateRef],
  )

  const classes = useStyles()
  const shouldEnableRetract: boolean =
    state.gameStatus === GameRunningStatus.RUNNING &&
    !!state.pieces.find(piece => piece.p === state.currentPlayerId)

  return (
    <div className={classes.toolbar}>
      <div className={cx(classes.item, classes.buttons)}>
        <Button
          variant="contained"
          color="inherit"
          startIcon={<RefreshIcon />}
          onClick={actions.start}
        >
          New
        </Button>
        <Button
          variant="contained"
          color="inherit"
          startIcon={<RetractIcon />}
          disabled={!shouldEnableRetract}
          onClick={actions.retract}
        >
          Retract
        </Button>
      </div>
      <div className={cx(classes.item, classes.state)}>
        <div key="state-buttons" className={classes.stateButtons}>
          {state.gameStatus === GameRunningStatus.RUNNING && (
            <Tooltip title="Pause">
              <IconButton color="primary" onClick={actions.pause}>
                <GameRunningIcon />
              </IconButton>
            </Tooltip>
          )}
        </div>
      </div>
      <Dialog
        container={props.containerRef.current}
        open={restartDialogVisible}
        onClose={() => setRestartDialogVisible(false)}
        aria-labelledby="confirm-to-restart"
      >
        <DialogContent>Are you sure you want to start a new game?</DialogContent>
        <DialogActions>
          <Button color="inherit" onClick={actions.closeDialog}>
            Cancel
          </Button>
          <Button color="primary" onClick={actions.restart}>
            Confirm
          </Button>
        </DialogActions>
      </Dialog>
    </div>
  )
}

GameToolbar.propTypes = {
  containerRef: PropTypes.any.isRequired,
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => ({
  toolbar: css`
    display: block;
    max-width: min(90vw, 400px);
    margin: auto;
  `,
  item: css`
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: flex-start;
    margin: 1rem 0;
    > * {
      margin-right: 1rem;
    }
  `,
  buttons: css`
    justify-content: space-around;
    > button {
      margin: 0 4px;
    }
  `,
  state: css`
    justify-content: center;
    margin: 2rem 0 0;
    height: 48px;
  `,
  stateButtons: css`
    flex: 0 1 auto;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0;
    user-select: none;
  `,
  elapsedTime: css`
    flex: 0 1 auto;
    display: flex;
    align-items: center;
    font-family: Consolas, 'Source Code Pro', 'Roboto Mono', monospace, sans-serif;
    color: #595959;
    user-select: none;
  `,
  score: css`
    flex: 0 1 auto;
    color: green;
    overflow: hidden;
    text-overflow: ellipsis;
    font-family: Consolas, 'Source Code Pro', 'Roboto Mono', monospace, sans-serif;
  `,
})
