import { GameRunningStatus } from '@kyokuya/react-game-core'
import type React from 'react'
import { GomokuInstructionType } from '../constant'
import type { IGomokuPieceData } from '../types'
import { calcGomokuBoard } from '../util/instruction'
import { checkCompleted } from '../util/status'
import type { IGomokuAction } from './action'
import { GomokuActionType } from './action'
import type { IGomokuState } from './state'

export const reducer: React.Reducer<IGomokuState, IGomokuAction> = (
  state: IGomokuState,
  action: IGomokuAction,
): IGomokuState => {
  switch (action.type) {
    case GomokuActionType.RESTART: {
      const { GOMOKU_SIZE, players } = state
      return {
        GOMOKU_SIZE,
        players,
        gameStatus: GameRunningStatus.PENDING,
        winner: -1,
        previousPlayerId: -1,
        currentPlayerId: 0,
        pieces: [],
        instructions: [],
        activatedCell: null,
        hintCell: null,
        gameTick: state.gameTick + 1,
        attemptTick: 0,
        hintTick: 0,
      }
    }
    case GomokuActionType.RESET: {
      const { GOMOKU_SIZE = state.GOMOKU_SIZE, players = state.players } = action.payload

      const { activatedCell } = state
      return {
        GOMOKU_SIZE,
        players,
        gameStatus: GameRunningStatus.PENDING,
        winner: -1,
        previousPlayerId: -1,
        currentPlayerId: 0,
        pieces: [],
        instructions: [],
        activatedCell,
        hintCell: null,
        gameTick: state.gameTick + 1,
        attemptTick: 0,
        hintTick: 0,
      }
    }
    case GomokuActionType.START: {
      // Not in pending state.
      if (state.gameStatus !== GameRunningStatus.PENDING) return state
      return { ...state, gameStatus: GameRunningStatus.RUNNING }
    }
    case GomokuActionType.PAUSE: {
      // Not in running state.
      if (state.gameStatus !== GameRunningStatus.RUNNING) return state
      return { ...state, gameStatus: GameRunningStatus.PAUSED }
    }
    case GomokuActionType.RESUME: {
      // Not in paused state.
      if (state.gameStatus !== GameRunningStatus.PAUSED) return state
      return { ...state, gameStatus: GameRunningStatus.RUNNING }
    }
    case GomokuActionType.ACTIVE: {
      const { r, c } = action.payload
      if (state.activatedCell?.r === r && state.activatedCell?.c === c) return state
      return { ...state, activatedCell: { r, c } }
    }
    case GomokuActionType.MOVE: {
      const { r, c } = action.payload
      const { GOMOKU_SIZE } = state
      if (state.pieces.find(piece => piece.r === r && piece.c === c)) return state

      const previousPlayerId: number = state.currentPlayerId
      const currentPlayerId: number = (previousPlayerId + 1) % state.players.length
      const piece: IGomokuPieceData = { r, c, p: previousPlayerId }

      const nextPieces: IGomokuPieceData[] = [...state.pieces, piece]
      const board = calcGomokuBoard(GOMOKU_SIZE, nextPieces)
      const isCompleted: boolean = checkCompleted(GOMOKU_SIZE, board)
      const isFinished = isCompleted || nextPieces.length === GOMOKU_SIZE * GOMOKU_SIZE

      return {
        ...state,
        gameStatus: isFinished ? GameRunningStatus.FINISHED : state.gameStatus,
        winner: isFinished && isCompleted ? previousPlayerId : -1,
        pieces: nextPieces,
        previousPlayerId,
        currentPlayerId,
        attemptTick: state.attemptTick + 1,
        instructions: [
          ...state.instructions,
          {
            type: GomokuInstructionType.MOVE,
            payload: piece,
            timestamp: new Date().toISOString(),
          },
        ],
      }
    }
    case GomokuActionType.RETRACT: {
      // Not in running state.
      if (state.gameStatus !== GameRunningStatus.RUNNING) return state

      let idx = state.pieces.length - 1
      for (; idx >= 0; --idx) {
        if (state.pieces[idx].p === state.currentPlayerId) break
      }

      // Not enough pieces to retract.
      if (idx < 0) return state

      const steps: number = state.pieces.length - idx
      const pieces: IGomokuPieceData[] = state.pieces.slice(0, state.pieces.length - steps)

      const previousPlayerId: number =
        pieces.length <= 0 ? -1 : (pieces.length - 1) % state.players.length
      const currentPlayerId: number = (previousPlayerId + 1) % state.players.length

      return {
        ...state,
        pieces: pieces,
        previousPlayerId,
        currentPlayerId,
        attemptTick: state.attemptTick + 1,
        instructions: [
          ...state.instructions,
          {
            type: GomokuInstructionType.RETRACT,
            payload: steps,
            timestamp: new Date().toISOString(),
          },
        ],
      }
    }
    default:
      return state
  }
}
